import {normalizedArticles} from '../fixtures'
import {ADD_COMMENT, DELETE_ARTICLE} from '../types'
import {arrToMap} from '../utils'
import {Map, fromJS} from 'immutable'

export default function (articles = fromJS(arrToMap(normalizedArticles)), action) {
    const {type, payload, randomId} = action

    switch (type) {
        case DELETE_ARTICLE:
            /*const articlesCopy = {...articles}
            delete articlesCopy[payload.id]
            return articlesCopy*/
            
            return articles.delete(payload.id)
        case ADD_COMMENT:
            /*const article = articles[payload.articleId]
            const comments = article.comments || []
            return {
                ...articles,
                [payload.articleId]: {
                    ...article,
                    comments: [...comments, randomId]
                }
            }*/

            return articles.updateIn([payload.id, 'comments'], (comments) => comments.push())
        default:
            return articles
    }
}
